        'cta.subtitle': 'Kostenlos und Open Source. Nach der Installation sofort nutzbar, ohne Registrierung. Alle Daten bleiben lokal.',
        'footer.name': 'Youran Tab',
        'nav.name': 'Youran Tab',
        'nav.home': 'Startseite',
